{
  /* AQICard.tsx */
}
export default function AQICard({ city }: { city: string }) {
  const [data, setData] = useState<AQIData | null>(null);
  const [error, setError] = useState(false);

  useEffect(() => {
    const fetchData = async () => {
      setError(false);
      setData(null);
      const result = await fetchAirQuality(city);
      if (!result) setError(true);
      else setData(result);
    };
    fetchData();
    const interval = setInterval(fetchData, 5 * 60 * 1000);
    return () => clearInterval(interval);
  }, [city]);

  if (error)
    return <div className="text-hint">Data not available for {city}</div>;
  if (!data) return <div className="text-hint">Loading {city}...</div>;

  return (
    <div className="p-4 rounded border bg w-full">
      <h2 className="text-xl font-bold">{city}</h2>
      <p>
        AQI:{" "}
        <span className={`px-2 py-1 rounded ${getAQIColor(data.aqi)}`}>
          {data.aqi}
        </span>
      </p>
      <p className="text-hint">Dominant Pollutant: {data.dominentpol}</p>
      <div className="mt-4">
        <Line data={chartData} options={chartOptions} />
      </div>
    </div>
  );
}
